1	import {ErrorBoundary} from '@rollbar/react';
2	import React, {forwardRef, useContext, useEffect, useRef} from 'react';
3	import SomethingWentWrongFallbackUI from 'components/SomethingWentWrongFallbackUI';
4	import RelatedProductsTabbedView from 'features/TabbedView';
5	import useRelatedProductsTabbedView from 'features/TabbedView/hooks/useRelatedProductsTabbedView';
6	import useRecommendedStyles from 'hooks/queries/recommendations';
7	import useRecoBrands from 'hooks/queries/recommendationsBrands';
8	import useRelatedStyles from 'hooks/queries/relatedStyles';
9	import useBreakpoint from 'hooks/useBreakpoint';
10	import CurrentSelectedColorContext from 'product_details_page/Context/colorContext';
11	import ProductContext from 'product_details_page/Context/productContext';
12	import isAlgoliaRecommendations from 'utils/isAlgoliaRecommendations';
13	import isCanadianStyle from 'utils/isCanadianStyle';
14	import {fireRecommendationsLoadedEvent} from 'utils/metrics/pdpRelatedStyles';
15	import AlternativeProducts from './AlternativeProducts';
16	import ComplementProducts from './ComplementProducts';
17	import useTrendingProductsByCategory from 'hooks/queries/useTrendingProductsByCategory';
18	
19	const RelatedProducts = forwardRef(function RelatedProducts(
20	  {forceTab, onEmpty},
21	  similarRef
22	) {
23	  const breakpoint = useBreakpoint();
24	  const {currentSelectedColor, singles} = useContext(
25	    CurrentSelectedColorContext
26	  );
27	  const {
28	    brand,
29	    id: styleId,
30	    isApparel,
31	    minQty,
32	    name,
33	    primaryCategoryId
34	  } = useContext(ProductContext);
35	  const firedAnalyticsEvent = useRef(false);
36	  const tabbedViewRef = useRef(null);
37	
38	  const {
39	    data: relatedProducts,
40	    isError: isRelatedProductsError,
41	    isFetched: isRelatedProductsFetched,
42	    isRefetching: isRelatedProductsRefetching,
43	    isSuccess: isRelatedProductsSuccess
44	  } = useRelatedStyles(styleId, currentSelectedColor?.id, {
45	    enabled: !!currentSelectedColor?.id,
46	    keepPreviousData: true,
47	    placeholderData: {
48	      alternatives: [],
49	      complements: []
50	    }
51	  });
52	
53	  const {
54	    data: recommendations,
55	    isFetched: isRecommendationsProductsFetched,
56	    isRefetching: isRecommendationsProductsRefetching,
57	    isSuccess: isRecommendationsProductsSuccess
58	  } = useRecommendedStyles(styleId, {
59	    enabled: !!currentSelectedColor?.id,
60	    keepPreviousData: false,
61	    placeholderData: {
62	      related_products: []
63	    },
64	    queryParams: {
65	      colorId: currentSelectedColor?.id,
66	      limit: 30
67	    }
68	  });
69	
70	  const {
71	    products: trendingProducts,
72	    isLoading: isTrendingProductsRefetching,
73	    isFetched: isTrendingProductsFetched
74	  } = useTrendingProductsByCategory({categoryId: primaryCategoryId});
75	
76	  const isCanadian = isCanadianStyle(name);
77	  const {
78	    data: recoBrandProducts,
79	    isFetched: isRecoBrandProductsFetched,
80	    isRefetching: isRecoBrandProductsRefetching
81	  } = useRecoBrands({
82	    enabled: !!currentSelectedColor?.id && !!brand && !isCanadian,
83	    keepPreviousData: false,
84	    placeholderData: {
85	      brand_products: []
86	    },
87	    queryParams: {
88	      brand,
89	      colorId: currentSelectedColor?.id,
90	      limit: 30,
91	      sortBy: 'rating', // can use 'category' as another option
92	      styleId
93	    }
94	  });
95	
96	  useEffect(() => {
97	    if (
98	      isRelatedProductsSuccess &&
99	      isRelatedProductsFetched &&
100	      !firedAnalyticsEvent.current
101	    ) {
102	      firedAnalyticsEvent.current = true;
103	      const hasRecommendations =
104	        relatedProducts.alternatives.length > 0 ||
105	        relatedProducts.complements.length > 0;
106	      fireRecommendationsLoadedEvent(styleId, hasRecommendations);
107	    }
108	  }, [
109	    isRelatedProductsSuccess,
110	    isRelatedProductsFetched,
111	    relatedProducts,
112	    styleId
113	  ]);
114	
115	  const alternativeProducts =
116	    isAlgoliaRecommendations() && isRecommendationsProductsSuccess
117	      ? recommendations?.related_products.filter(
118	          (item) => item?.primary_category_id === primaryCategoryId
119	        )
120	      : relatedProducts?.alternatives;
121	
122	  const {
123	    hasAnyData,
124	    relatedProductsActiveTab,
125	    setRelatedProductsActiveTab,
126	    shouldTabbedViewRender,
127	    tabbedViewIsLoading,
128	    tabbedViewProducts,
129	    tabs
130	  } = useRelatedProductsTabbedView({
131	    alternativeProducts,
132	    brand,
133	    breakpoint,
134	    forceTab,
135	    isApparel,
136	    isNoMinimumSelected: singles,
137	    isRecoBrandProductsFetched,
138	    isRecoBrandProductsRefetching,
139	    isRecommendationsProductsFetched,
140	    isRecommendationsProductsRefetching,
141	    isRelatedProductsFetched,
142	    isRelatedProductsRefetching,
143	    isTrendingProductsFetched,
144	    isTrendingProductsRefetching,
145	    minQty,
146	    primaryCategoryId,
147	    recoBrandProducts,
148	    recommendations,
149	    relatedProducts,
150	    trendingProducts
151	  });
152	
153	  useEffect(() => {
154	    if (tabbedViewProducts.length === 0 && !tabbedViewIsLoading && onEmpty) {
155	      onEmpty();
156	    }
157	  }, [tabbedViewProducts.length, tabbedViewIsLoading, onEmpty]);
158	
159	  if (isRelatedProductsError) {
160	    return null;
161	  }
162	
163	  if (!tabbedViewIsLoading && tabbedViewProducts.length === 0) {
164	    return null;
165	  }
166	
167	  return (
168	    <ErrorBoundary fallbackUI={SomethingWentWrongFallbackUI}>
169	      {shouldTabbedViewRender && (
170	        <RelatedProductsTabbedView
171	          relatedProductsRef={tabbedViewRef}
172	          tabs={tabs}
173	          activeTab={relatedProductsActiveTab}
174	          onTabChange={setRelatedProductsActiveTab}
175	          isLoading={tabbedViewIsLoading}
176	          products={tabbedViewProducts}
177	          hasAnyData={hasAnyData}
178	        />
179	      )}
180	      {!shouldTabbedViewRender && alternativeProducts?.length > 0 && (
181	        <AlternativeProducts
182	          alternativeProducts={alternativeProducts}
183	          similarRef={similarRef}
184	        />
185	      )}
186	      {!shouldTabbedViewRender &&
187	        isRelatedProductsFetched &&
188	        (relatedProducts?.complements?.length > 0 ||
189	          alternativeProducts?.length > 0) && (
190	          <ComplementProducts
191	            complementProducts={relatedProducts?.complements ?? []}
192	            alternativeProducts={alternativeProducts ?? []}
193	          />
194	        )}
195	    </ErrorBoundary>
196	  );
197	});
198	
199	export default RelatedProducts;
