1	import PropTypes from 'prop-types';
2	import React, {useCallback, useEffect, useMemo, useState} from 'react';
3	import {semantics} from '@customink/design-tokens';
4	import {
5	  PDP_RELATED_PRODUCTS_VIEW_TYPE,
6	  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
7	  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
8	  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
9	} from 'constants/pdpRelatedProducts';
10	import useIntersectionObserverOnce from 'hooks/useIntersectionObserverOnce';
11	import ProductDetailsRow from 'product_details_page/ProductDetailsRow';
