28	const CardsComponent = ({children, isLoading, length, separatedView}) => {
29	  if (!isLoading && length === 0) {
30	    return <EmptyStateCardsView />;
31	  }
32	  if (isLoading) {
33	    return <Loader />;
34	  }
35	  if (length <= 4) {
36	    return <StyledRecoBox>{children}</StyledRecoBox>;
37	  }
38	
39	  return (
40	    <CarouselCardsView separatedView={separatedView}>
41	      {children}
42	    </CarouselCardsView>
43	  );
44	};
45	
46	CardsComponent.propTypes = {
47	  separatedView: PropTypes.bool.isRequired,
48	  children: PropTypes.node.isRequired,
49	  isLoading: PropTypes.bool.isRequired,
50	  length: PropTypes.number.isRequired,
51	  activeTab: PropTypes.string.isRequired
52	};
53	
54	const getWidgetType = (activeTab) => {
55	  switch (activeTab) {
56	    case RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE:
57	      return 'you_may_also_like';
58	    case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY:
59	      return 'budget_friendly';
60	    case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
61	      return 'trending';
62	    default:
63	      return 'recommended';
64	  }
65	};
66	
67	const getTitle = (type, activeTab) => {
68	  if (type === PDP_RELATED_PRODUCTS_VIEW_TYPE.tabbed) {
69	    return 'Recommended for you';
70	  }
71	  switch (activeTab) {
72	    case RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE:
73	      return 'Shop Similar Styles';
74	    case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY:
75	      return 'Budget Friendly Options';
76	    case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
77	      return 'Trending Products';
78	    default:
79	      break;
80	  }
81	
82	  return 'Recommended for you';
83	};
84	
85	const RelatedProductsTabbedView = ({
86	  type = PDP_RELATED_PRODUCTS_VIEW_TYPE.tabbed,
87	  activeTab = RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
88	  hasAnyData = true,
89	  isLoading,
90	  onTabChange,
91	  products = [],
92	  relatedProductsRef,
93	  tabs = []
94	}) => {
95	  const [isVisible, setIsVisible] = useState(true);
96	
97	  useEffect(() => {
98	    if (!hasAnyData && !isLoading) {
99	      setIsVisible(false);
100	    } else if (hasAnyData || isLoading) {
101	      setIsVisible(true);
102	    }
103	  }, [hasAnyData, isLoading]);
104	  useIntersectionObserverOnce(relatedProductsRef, () => {
105	    fireTabbedViewEvent({
106	      eventType: EVENT_TYPE.VIEWED
107	    });
108	  });
109	  const handleCardClick = useCallback(
110	    (styleId, href) => (event) => {
111	      fireTabbedViewEventWithCallback({
112	        callback: () => {
113	          handleRightClick(event, href);
114	        },
115	        eventData: {
116	          activeTab,
117	          eventType: EVENT_TYPE.ITEM_CLICKED,
118	          styleId
119	        }
120	      });
121	    },
122	    [activeTab]
123	  );
124	  const slides = useMemo(
125	    () =>
126	      products.map((product) => (
127	        <ProductDetailsCard
128	          sx={{
129	            width: '100%',
130	            '&:hover': {
131	              boxShadow: 'none'
132	            },
133	            '& .MuiCardContent-root': {
134	              display: 'flex',
135	              flex: '1 1 auto',
136	              flexDirection: 'column',
137	              gap: `${semantics.units.space.componentLayout.xs} !important`,
138	              minHeight: '7.5rem !important',
139	              padding: `${semantics.units.space.componentLayout.sm} ${semantics.units.space.componentLayout.xs} !important`,
140	              fontFamily: 'SharpSans, sans-serif',
141	              [`@media (min-width: ${semantics.units.size.breakpoint.desktop})`]:
142	                {
143	                  padding: `${semantics.units.space.componentLayout.sm} ${semantics.units.space.componentLayout.md} !important`
144	                }
145	            },
146	            '& .rpc-image-wrapper': {
147	              flexShrink: 0,
148	              height: '9rem !important',
149	              paddingTop: '0 !important',
150	              width: '100% !important',
151	              [`@media (min-width: ${semantics.units.size.breakpoint.desktop})`]:
152	                {
153	                  height: '13rem !important'
154	                },
155	              [`@media (min-width: ${semantics.units.size.breakpoint.desktopXL})`]:
156	                {
157	                  height: '18rem !important'
158	                }
159	            },
160	            '& [data-testid="reco-product-name"]': {
161	              fontFamily: 'SharpSans, sans-serif',
162	              marginBottom: '0 !important',
163	              minHeight: '2rem',
164	              WebkitLineClamp: 2
165	            },
166	            '& [data-testid="product-price-container"]': {
167	              fontFamily: 'SharpSans, sans-serif',
168	              color: semantics.light.neutral.text.secondary
169	            },
170	            span: {
171	              fontFamily: 'SharpSans, sans-serif'
172	            },
173	            height: '19.4rem',
174	            [`@media (min-width: ${semantics.units.size.breakpoint.desktop}) and (max-width: 1299px)`]:
175	              {
176	                height: '23rem'
177	              },
178	            [`@media (min-width: ${semantics.units.size.breakpoint.desktopXL})`]:
179	              {
180	                height: '27.5rem'
181	              }
182	          }}
183	          key={`related-styles-${activeTab.toLowerCase()}-${product.name}`}
184	          onClick={handleCardClick(
185	            product.style_id,
186	            createRecoCardLinkHref({
187	              stylePath: product.link,
188	              colorId: product.color
189	            })
190	          )}
191	          linkHref={createRecoCardLinkHref({
192	            stylePath: product.link,
193	            colorId: product.color
194	          })}
195	          imageSrc={product.image_src}
196	          imageSrcSet={product.image_srcset}
197	          minQty={product.min_qty}
198	          name={product.name}
199	          ratingCount={product.rating_count}
200	          ratingScore={product.rating_score}
201	          sizing={product.sizing}
202	          generalComments={product.general_comments}
203	          defaultUnitPrices={product.default_unit_prices}
204	          primaryCategoryId={product.primary_category_id}
205	          styleType={product.style_type}
206	          defaultQuoteQty={product.default_quote_qty}
207	          productId={product.style_id}
208	          widgetType={getWidgetType(activeTab)}
209	          categories={
210	            product.categories || [
211	              {
212	                id: product.primary_category_id,
213	                name: product.primary_category_name
214	              }
215	            ]
216	          }
217	        />
218	      )),
219	    [activeTab, handleCardClick, products]
220	  );
221	
222	  return (
223	    <div
224	      style={{
225	        maxHeight: isVisible ? '62.5rem' : '0',
226	        opacity: isVisible ? 1 : 0,
227	        overflow: 'hidden',
228	        transition: 'max-height 0.5s ease-out, opacity 0.5s ease-out'
229	      }}>
230	      <ProductDetailsRow
231	        childrenRef={relatedProductsRef}
232	        title={getTitle(type, activeTab)}>
233	        <Tabs tabs={tabs} activeTab={activeTab} onTabChange={onTabChange} />
234	        <CardsComponent
235	          key={activeTab}
236	          isLoading={isLoading}
237	          length={products.length}
238	          activeTab={activeTab}>
239	          {slides}
240	        </CardsComponent>
241	      </ProductDetailsRow>
242	    </div>
243	  );
244	};
245	
246	RelatedProductsTabbedView.propTypes = {
247	  type: PropTypes.string,
248	  activeTab: PropTypes.string,
249	  hasAnyData: PropTypes.bool,
250	  isLoading: PropTypes.bool,
251	  onTabChange: PropTypes.func,
252	  products: PropTypes.arrayOf(
253	    PropTypes.shape({
254	      color: PropTypes.number,
255	      general_comments: PropTypes.string,
256	      image_src: PropTypes.string,
257	      image_srcset: PropTypes.string,
258	      link: PropTypes.string,
259	      min_qty: PropTypes.number,
260	      name: PropTypes.string,
261	      rating_count: PropTypes.string,
262	      rating_score: PropTypes.string,
263	      sizing: PropTypes.string,
264	      style_id: PropTypes.number
265	    })
266	  ),
267	  relatedProductsRef: PropTypes.object,
268	  tabs: PropTypes.arrayOf(
269	    PropTypes.shape({
270	      label: PropTypes.string,
271	      value: PropTypes.string
272	    })
273	  )
274	};
275	
276	export default RelatedProductsTabbedView;
