1	import {useMemo} from 'react';
2	import {
3	  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
4	  RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS,
5	  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
6	  RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
7	  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
8	  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS,
9	  RELATED_PRODUCTS_TABS
10	} from 'constants/pdpRelatedProducts';
11	import {filterByCategory} from './useRelatedProductsData';
12	
13	export default function useRelatedProductsTabs({
14	  forceTab,
15	  isApparel,
16	  isNoMinimumSelected,
17	  isRecommendationsProductsFetched,
18	  isRelatedProductsFetched,
19	  minQty,
20	  primaryCategoryId,
21	  recoBrandProducts,
22	  recommendations,
23	  relatedProducts
24	}) {
25	  const tabsToShow = useMemo(
26	    () =>
27	      Object.values(RELATED_PRODUCTS_TABS).filter(({value}) => {
28	        const filteredProducts = filterByCategory(
29	          recommendations?.related_products,
30	          primaryCategoryId
31	        );
32	
33	        if (value === RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS) {
34	          return false;
35	        }
36	        if (value === RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES) {
37	          if (isApparel) {
38	            return (
39	              !isRelatedProductsFetched ||
40	              relatedProducts?.complements?.length > 0
41	            );
42	          }
43	          return false;
44	        }
45	        if (value === RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND) {
46	          return recoBrandProducts?.brand_products?.length > 0;
47	        }
48	        if (value === RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS) {
49	          const lowerMinimumProducts = filteredProducts?.filter(
50	            (product) => product.min_qty < minQty
51	          );
52	
53	          return !isNoMinimumSelected && lowerMinimumProducts?.length > 0;
54	        }
55	        return (
56	          !isRecommendationsProductsFetched || filteredProducts?.length > 0
57	        );
58	      }),
59	    [
60	      isApparel,
61	      isNoMinimumSelected,
62	      isRecommendationsProductsFetched,
63	      isRelatedProductsFetched,
64	      minQty,
65	      primaryCategoryId,
66	      recoBrandProducts?.brand_products?.length,
67	      recommendations,
68	      relatedProducts
69	    ]
70	  );
71	
72	  const tabOrder = useMemo(() => {
73	    return [
74	      RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
75	      RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
76	      ...[
77	        RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
78	        RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
79	        RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS
80	      ].sort(() => Math.random() - 0.5)
81	    ];
82	  }, []);
83	
84	  const tabs = useMemo(() => {
85	    return tabsToShow.sort((a, b) => {
86	      return tabOrder.indexOf(a.value) - tabOrder.indexOf(b.value);
87	    });
88	  }, [tabsToShow, tabOrder]);
89	
90	  return {
91	    tabOrder,
92	    tabs,
93	    tabsToShow
94	  };
95	}
