1	import {useEffect, useMemo, useState} from 'react';
2	import {
3	  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
4	  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
5	  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
6	} from 'constants/pdpRelatedProducts';
7	import isAlgoliaRecommendations from 'utils/isAlgoliaRecommendations';
8	
9	export default function useRelatedProductsState({
10	  breakpoint,
11	  forceTab,
12	  isRecommendationsProductsFetched,
13	  isRecommendationsProductsRefetching,
14	  isRelatedProductsFetched,
15	  isRelatedProductsRefetching,
16	  isTrendingProductsFetched,
17	  isTrendingProductsRefetching,
18	  tabs = []
19	}) {
20	  const [relatedProductsActiveTab, setRelatedProductsActiveTab] = useState(
21	    RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE
22	  );
23	
24	  const isMobile = breakpoint === 'xs' || breakpoint === 'sm';
25	  const shouldTabbedViewRender = !isMobile && isAlgoliaRecommendations();
26	
27	  const tabbedViewIsLoading = useMemo(() => {
28	    if (
29	      relatedProductsActiveTab === RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES
30	    ) {
31	      return !isRelatedProductsFetched || isRelatedProductsRefetching;
32	    }
33	
34	    if (relatedProductsActiveTab === RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS) {
35	      return !isTrendingProductsFetched || isTrendingProductsRefetching;
36	    }
37	
38	    return (
39	      !isRecommendationsProductsFetched || isRecommendationsProductsRefetching
40	    );
41	  }, [
42	    relatedProductsActiveTab,
43	    isRecommendationsProductsFetched,
44	    isRecommendationsProductsRefetching,
45	    isRelatedProductsFetched,
46	    isRelatedProductsRefetching,
47	    isTrendingProductsFetched,
48	    isTrendingProductsRefetching
49	  ]);
50	
51	  const hasAnyData = useMemo(() => {
52	    return tabs.length > 0;
53	  }, [tabs.length]);
54	
55	  useEffect(() => {
56	    if (tabs.length > 0) {
57	      const activeTabExists = tabs.some(
58	        (tab) => tab.value === relatedProductsActiveTab
59	      );
60	      if (!activeTabExists) {
61	        setRelatedProductsActiveTab(tabs[0].value);
62	      }
63	      if (forceTab && forceTab !== relatedProductsActiveTab) {
64	        setRelatedProductsActiveTab(forceTab);
65	      }
66	    }
67	  }, [tabs, relatedProductsActiveTab, forceTab]);
68	
69	  return {
70	    hasAnyData,
71	    relatedProductsActiveTab,
72	    setRelatedProductsActiveTab,
73	    shouldTabbedViewRender,
74	    tabbedViewIsLoading
75	  };
76	}
