1	import {useMemo} from 'react';
2	import {
3	  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
4	  RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS,
5	  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
6	  RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
7	  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
8	} from 'constants/pdpRelatedProducts';
9	import {searchParams} from 'src/utils/url';
10	import DEFAULT_PRICING_ALGORITHM from 'constants/defaultPriceAlgorithm';
11	import {
12	  BLANK_PRICE_QTY,
13	  unbundledPriceSortEligible
14	} from 'utils/abTests/unbundledPriceTest';
15	
16	export const filterByCategory = (products, categoryId) => {
17	  if (!products || !categoryId) return products;
18	  const filteredProducts = products.filter(
