24	export const filterByBrand = (products, brand) => {
25	  if (!products) return products;
26	  if (!brand || brand === '') return [];
27	  return products.filter((item) =>
28	    item.brand?.find(
29	      (recoBrand) =>
30	        recoBrand !== '' && recoBrand.toLowerCase() === brand.toLowerCase()
31	    )
32	  );
33	};
