35	export const getMinPrice = ({product, useBlankPrice = false}) => {
36	  const {
37	    default_unit_prices: defaultUnitPrices,
38	    minQty,
39	    default_quote_qty: defaultQuoteQty
40	  } = product;
41	
42	  if (useBlankPrice) {
43	    const blankPriceEntry = defaultUnitPrices.find(
44	      (price) =>
45	        price?.quantity === BLANK_PRICE_QTY &&
46	        price?.algorithm === DEFAULT_PRICING_ALGORITHM &&
47	        price?.price !== null &&
48	        price?.price !== undefined
49	    );
50	    if (blankPriceEntry) {
51	      return {price: Number(blankPriceEntry.price)};
52	    }
53	    return {price: Number.MAX_SAFE_INTEGER};
54	  }
55	
56	  let quoteQtyParam;
57	  try {
58	    quoteQtyParam = searchParams()?.get('quote_qty');
59	  } catch {
60	    quoteQtyParam = null;
61	  }
62	
63	  const useNoMinimum =
64	    quoteQtyParam === 'min' &&
65	    minQty === 1 &&
66	    defaultUnitPrices.find((price) => price?.quantity === 1);
67	
68	  const expectedQuantity = useNoMinimum ? 1 : defaultQuoteQty;
69	
70	  if (
71	    expectedQuantity === null ||
72	    expectedQuantity === undefined ||
73	    typeof expectedQuantity !== 'number'
74	  ) {
75	    return {price: Number.MAX_SAFE_INTEGER};
76	  }
77	
78	  const productPrices = defaultUnitPrices.find(
79	    (price) =>
80	      price?.quantity === expectedQuantity &&
81	      price?.algorithm === DEFAULT_PRICING_ALGORITHM &&
82	      price?.price !== null &&
83	      price?.price !== undefined
84	  );
85	
86	  if (!productPrices) {
87	    return {price: Number.MAX_SAFE_INTEGER};
88	  }
89	
90	  const {price, regular_unit_price} = productPrices;
91	
92	  const numPrice = Number(price);
93	  const numRegularPrice = Number(regular_unit_price);
94	
95	  if (
96	    !isNaN(numPrice) &&
97	    !isNaN(numRegularPrice) &&
98	    numRegularPrice > 0 &&
99	    numRegularPrice < numPrice
100	  ) {
101	    return {price: numRegularPrice};
102	  }
103	
104	  if (!isNaN(numPrice)) {
105	    return {price: numPrice};
106	  }
107	
108	  return {price: Number.MAX_SAFE_INTEGER};
109	};
