111	export default function useRelatedProductsData({
112	  alternativeProducts,
113	  minQty,
114	  primaryCategoryId,
115	  recoBrandProducts,
116	  recommendations,
117	  relatedProducts,
118	  relatedProductsActiveTab,
119	  shouldTabbedViewRender,
120	  trendingProducts
121	}) {
122	  const tabbedViewProducts = useMemo(() => {
123	    if (!shouldTabbedViewRender) {
124	      return alternativeProducts.slice(0, 4);
125	    }
126	
127	    let products;
128	    switch (relatedProductsActiveTab) {
129	      case RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES:
130	        products = relatedProducts?.complements;
131	        break;
132	      case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY: {
133	        const useBlankPrice = unbundledPriceSortEligible(primaryCategoryId);
134	        products = filterByCategory(
135	          recommendations?.related_products,
136	          primaryCategoryId
137	        );
138	        if (products) {
139	          products = [...products].sort(
140	            (a, b) =>
141	              getMinPrice({product: a, useBlankPrice}).price -
142	              getMinPrice({product: b, useBlankPrice}).price
143	          );
144	        }
145	        break;
146	      }
147	      case RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND:
148	        products = recoBrandProducts?.brand_products || [];
149	        break;
150	      case RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS:
151	        products = filterByCategory(
152	          recommendations?.related_products,
153	          primaryCategoryId
154	        )
155	          ?.filter((product) => product.min_qty < minQty)
156	          ?.sort((a, b) => a.min_qty - b.min_qty);
157	        break;
158	      case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
159	        products = trendingProducts;
160	        break;
161	      default:
162	        products = filterByCategory(
163	          recommendations?.related_products,
164	          primaryCategoryId
165	        );
166	    }
167	    return products;
168	  }, [
169	    alternativeProducts,
170	    minQty,
171	    primaryCategoryId,
172	    recoBrandProducts?.brand_products,
173	    recommendations,
174	    relatedProducts,
175	    relatedProductsActiveTab,
176	    shouldTabbedViewRender,
177	    trendingProducts
178	  ]);
179	
180	  return {
181	    filterByBrand,
182	    filterByCategory,
183	    getMinPrice,
184	    tabbedViewProducts
185	  };
186	}
